// Validate incoming webhook payload
const body = $input.first().json.body || $input.first().json;

if (!body.file_url && !body.file_base64) {
  throw new Error('Missing file_url or file_base64 in payload');
}

return [{
  json: {
    file_url: body.file_url || null,
    file_base64: body.file_base64 || null,
    filename: body.filename || 'document.pdf',
    source: body.source || 'webhook',
    received_at: new Date().toISOString()
  }
}];

const result = $input.first().json;

// Route based on confidence and review status
const confidence = result.overall_confidence || 0;
const status = result.review_status;

return [{
  json: {
    ...result,
    routing: {
      needs_review: status === 'needs_review',
      auto_approved: status === 'approved',
      has_error: result.status === 'error',
      confidence_pct: Math.round(confidence * 100)
    }
  }
}];

// Build Slack notification for HIGH CONFIDENCE auto-approved invoices
const r = $input.first().json;
const inv = r.invoice_data || {};

const lineItemsText = (inv.line_items || []).slice(0, 3)
  .map(item => `  • ${item.description}: ${item.total || 'N/A'}`)
  .join('\n');

return [{
  json: {
    blocks: [
      {
        type: 'header',
        text: { type: 'plain_text', text: '✅ Invoice Auto-Processed' }
      },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*Vendor:*\n${inv.vendor_name || 'Unknown'}` },
          { type: 'mrkdwn', text: `*Invoice #:*\n${inv.invoice_number || 'N/A'}` },
          { type: 'mrkdwn', text: `*Total:*\n${inv.currency} ${inv.total_amount || 'N/A'}` },
          { type: 'mrkdwn', text: `*Confidence:*\n${r.routing.confidence_pct}%` }
        ]
      },
      {
        type: 'section',
        text: { type: 'mrkdwn', text: `*Top Line Items:*\n${lineItemsText || 'None'}` }
      }
    ]
  }
}];

// Build Slack alert for LOW CONFIDENCE — needs human review
const r = $input.first().json;
const inv = r.invoice_data || {};

const reviewUrl = `http://localhost:8000/docs#/Human%20Review/approve_review__job_id__approve_patch`;

return [{
  json: {
    blocks: [
      {
        type: 'header',
        text: { type: 'plain_text', text: '⚠️ Invoice Needs Review' }
      },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*Job ID:*\n${r.job_id}` },
          { type: 'mrkdwn', text: `*File:*\n${r.filename}` },
          { type: 'mrkdwn', text: `*Confidence:*\n${r.routing.confidence_pct}%` },
          { type: 'mrkdwn', text: `*Vendor:*\n${inv.vendor_name || 'Could not extract'}` }
        ]
      },
      {
        type: 'section',
        text: { type: 'mrkdwn', text: `*Issues:*\n${r.review_notes || 'Low confidence extraction'}` }
      },
      {
        type: 'actions',
        elements: [
          {
            type: 'button',
            text: { type: 'plain_text', text: 'Review Now' },
            url: `http://localhost:8000/docs`,
            style: 'primary'
          }
        ]
      }
    ]
  }
}];

const stats = $input.first().json;
return [{
  json: {
    text: `📋 *DocFlow Review Queue*: ${stats.pending_review} invoices awaiting review | Avg confidence: ${Math.round(stats.avg_confidence * 100)}% | Total processed: ${stats.total_documents}`
  }
}];
